// Valida e extrai payload de update_services
// Input esperado: { ACTION: string, RUNNING_STATUS: integer }

const body = $input.first().json.body || {};
const ACTION = (body.ACTION || '').toString().trim();
const RUNNING_STATUS = parseInt(body.RUNNING_STATUS, 10);

// Validações
const errors = [];

if (!ACTION) {
  errors.push('Campo ACTION é obrigatório');
}

if (isNaN(RUNNING_STATUS)) {
  errors.push('Campo RUNNING_STATUS deve ser um número inteiro');
}

if (![0, 1, 2, -1].includes(RUNNING_STATUS)) {
  errors.push('RUNNING_STATUS deve ser 0, 1, 2 ou -1');
}

if (errors.length > 0) {
  return [{
    json: {
      _valid: false,
      _errors: errors,
      _statusCode: 400
    }
  }];
}

// Payload válido
return [{
  json: {
    _valid: true,
    ACTION: ACTION,
    RUNNING_STATUS: RUNNING_STATUS,
    _receivedAt: new Date().toISOString(),
    _routePath: 'update_services'
  }
}];

// Log estruturado (sem campos sensíveis)
const input = $input.first().json;

const logEntry = {
  timestamp: new Date().toISOString(),
  route: 'update_services',
  method: 'PUT',
  action: input.ACTION,
  status_updated_to: input.RUNNING_STATUS,
  success: true
};

console.log('[VHSYS] update_services:', JSON.stringify(logEntry));

return {
  statusCode: 201,
  body: {
    ok: true,
    message: 'Update extension service status'
  }
};

// Resposta de erro para validação falhou
const input = $input.first().json;

const logEntry = {
  timestamp: new Date().toISOString(),
  route: 'update_services',
  method: 'PUT',
  errors: input._errors,
  success: false
};

console.log('[VHSYS] update_services ERROR:', JSON.stringify(logEntry));

return {
  statusCode: 400,
  body: {
    ok: false,
    error: 'Validation failed',
    details: input._errors
  }
};
